from collections import defaultdict, deque

def topo(items, edges):
    indeg = defaultdict(int); g = defaultdict(list)
    for a,b in edges:
        g[a].append(b); indeg[b] += 1
    q = deque([x for x in items if indeg[x]==0])
    out = []
    while q:
        n = q.popleft(); out.append(n)
        for m in g[n]:
            indeg[m]-=1
            if indeg[m]==0: q.append(m)
    return out

